from common import *
import numpy as np
from typing import *

# concepts:
# pattern extraction, line drawing

# description:
# In the input you will see a grid with various colored lines intersecting.
# To make the output grid, you should identify the longest continuous line of each color.
# Then, draw an additional line of the same color at the midpoint of the longest line's length.

def main(input_grid: np.ndarray) -> np.ndarray:
    output_grid = np.copy(input_grid)

    # Initialize a dictionary to hold the longest lines' information by color
    longest_lines = {}

    # Check for horizontal lines
    for row in range(output_grid.shape[0]):
        current_color = None
        current_length = 0
        for col in range(output_grid.shape[1]):
            color = output_grid[row, col]
            if color != Color.BLACK:
                if color == current_color:
                    current_length += 1
                else:
                    if current_color is not None and current_color not in longest_lines:
                        longest_lines[current_color] = (row, col - current_length, current_length)
                    elif current_color is not None:
                        if current_length > longest_lines[current_color][2]:
                            longest_lines[current_color] = (row, col - current_length, current_length)
                    current_color = color
                    current_length = 1
            else:
                if current_color is not None:
                    if current_color not in longest_lines:
                        longest_lines[current_color] = (row, col - current_length, current_length)
                    elif current_length > longest_lines[current_color][2]:
                        longest_lines[current_color] = (row, col - current_length, current_length)
                current_color = None
                current_length = 0
        # Check at the end of the row
        if current_color is not None:
            if current_color not in longest_lines:
                longest_lines[current_color] = (row, col - current_length, current_length)
            elif current_length > longest_lines[current_color][2]:
                longest_lines[current_color] = (row, col - current_length, current_length)

    # Check for vertical lines
    for col in range(output_grid.shape[1]):
        current_color = None
        current_length = 0
        for row in range(output_grid.shape[0]):
            color = output_grid[row, col]
            if color != Color.BLACK:
                if color == current_color:
                    current_length += 1
                else:
                    if current_color is not None and current_color not in longest_lines:
                        longest_lines[current_color] = (row - current_length, col, current_length)
                    elif current_color is not None:
                        if current_length > longest_lines[current_color][2]:
                            longest_lines[current_color] = (row - current_length, col, current_length)
                    current_color = color
                    current_length = 1
            else:
                if current_color is not None:
                    if current_color not in longest_lines:
                        longest_lines[current_color] = (row - current_length, col, current_length)
                    elif current_length > longest_lines[current_color][2]:
                        longest_lines[current_color] = (row - current_length, col, current_length)
                current_color = None
                current_length = 0
        # Check at the end of the column
        if current_color is not None:
            if current_color not in longest_lines:
                longest_lines[current_color] = (row - current_length, col, current_length)
            elif current_length > longest_lines[current_color][2]:
                longest_lines[current_color] = (row - current_length, col, current_length)

    # Draw a line through the midpoint of the longest lines found
    for color, (start_row, start_col, length) in longest_lines.items():
        if length > 0:
            midpoint = start_row + length // 2
            if length % 2 == 0:
                # Draw horizontally
                draw_line(output_grid, start_row, start_col, end_x=start_row, end_y=start_col + length, color=color)
            else:
                # Draw vertically
                draw_line(output_grid, midpoint, start_col, length=length, direction=(1, 0), color=color)

    return output_grid

def generate_input() -> np.ndarray:
    # Generate the background grid with size of n x m.
    n, m = np.random.randint(15, 25), np.random.randint(15, 25)
    grid = np.zeros((n, m), dtype=int)

    # Randomly generate lines of different colors
    colors = np.random.choice(Color.NOT_BLACK, size=np.random.randint(3, 5), replace=False)

    for color in colors:
        # Randomly choose start and end points for the lines
        for _ in range(np.random.randint(1, 4)):  # 1 to 3 lines of each color
            if np.random.choice([True, False]):
                # Horizontal line
                row = np.random.randint(0, n)
                col_start = np.random.randint(0, m - 5)
                length = np.random.randint(5, 10)
                draw_line(grid, row, col_start, length=length, direction=(0, 1), color=color)
            else:
                # Vertical line
                col = np.random.randint(0, m)
                row_start = np.random.randint(0, n - 5)
                length = np.random.randint(5, 10)
                draw_line(grid, row_start, col, length=length, direction=(1, 0), color=color)

    return grid
